define i8 @mul_add_common_factor_0(i8 %x) {
  %a0 = add i8 %x, -1
  %m = mul i8 %x, 5
  %a1 = add i8 %a0, %m
  ret i8 %a1
}

define i16 @mul_add_common_factor_1(i16 %x) {
  %a0 = add i16 %x, -1
  %m = mul i16 %x, 4
  %a1 = add i16 %m, %a0
  ret i16 %a1
}

define i32 @mul_add_common_factor_2(i32 %x, i32 %y) {
  %a0 = add i32 %x, %y
  %m = mul i32 %x, 4
  %a1 = add i32 %a0, %m
  ret i32 %a1
}

define i32 @mul_add_common_factor_2_commute(i32 %x, i32 %y) {
  %a0 = add i32 %y, %x
  %m = mul i32 %x, 4
  %a1 = add i32 %a0, %m
  ret i32 %a1
}

define i128 @mul_add_common_factor_3(i128 %x, i128 %t) {
  %a0 = add i128 %x, 2
  %m = mul i128 %x, %t
  %a1 = add i128 %a0, %m
  ret i128 %a1
}

define i128 @mul_add_common_factor_3_commute(i128 %x, i128 %t) {
  %a0 = add i128 %x, 2
  %m = mul i128 %t, %x
  %a1 = add i128 %a0, %m
  ret i128 %a1
}

define <2 x i8> @mul_add_common_factor_5(<2 x i8> %x) {
  %a0 = add <2 x i8> %x, <i8 3, i8 3>
  %m = mul <2 x i8> %x, <i8 4, i8 4>
  %a1 = add <2 x i8> %m, %a0
  ret <2 x i8> %a1
}

define i16 @shl_add_common_factor_1(i16 %x) {
  %a0 = add i16 %x, -1
  %s = shl i16 %x, 2
  %a1 = add i16 %s, %a0
  ret i16 %a1
}

define i32 @shl_add_common_factor_2(i32 %x, i32 %y) {
  %a0 = add i32 %x, %y
  %s = shl i32 %x, 2
  %a1 = add i32 %a0, %s
  ret i32 %a1
}

define i32 @shl_add_common_factor_2_commute(i32 %x, i32 %y) {
  %a0 = add i32 %y, %x
  %s = shl i32 %x, 2
  %a1 = add i32 %a0, %s
  ret i32 %a1
}

define <2 x i64> @shl_add_common_factor_5(<2 x i64> %x) {
  %a0 = add <2 x i64> %x, <i64 3, i64 3>
  %s = shl <2 x i64> %x, <i64 2, i64 2>
  %a1 = add <2 x i64> %s, %a0
  ret <2 x i64> %a1
}
